use std::collections::HashMap;
fn solve(arr: &[String], k: usize) -> Vec<String> {
  let mut freq: HashMap<String,i64> = HashMap::new();
  for x in arr { *freq.entry(x.clone()).or_insert(0) += 1; }
  let mut list: Vec<(String,i64)> = freq.into_iter().collect();
