// Caso: Validar RUT chileno | Nivel: Intermedio | Categoría: Validación
fn solve(rut: &str) -> bool {
  let clean: String = rut.chars()
    .filter(|c| *c != '.' && *c != '-' && !c.is_whitespace())
    .collect::<String>()
    .to_uppercase();

  if clean.len() < 2 { return false; }

  let (body, dv) = clean.split_at(clean.len()-1);
  if !body.chars().all(|c| c.is_ascii_digit()) { return false; }

  let mut sum: i32 = 0;
  let mut mul: i32 = 2;
  for ch in body.chars().rev() {
    let d = ch.to_digit(10).unwrap() as i32;
    sum += d * mul;
    mul = if mul == 7 { 2 } else { mul + 1 };
  }

  let modv = 11 - (sum % 11);
  let dv_calc = if modv == 11 { '0' } else if modv == 10 { 'K' } else { char::from_digit(modv as u32, 10).unwrap() };
  dv.chars().next().unwrap() == dv_calc
}

