use std::error::Error;

fn solve() -> Result<(), Box<dyn Error>> {
  let mut rdr = csv::Reader::from_path("input.csv")?;
  let headers = rdr.headers()?.clone();
  let email_idx = headers.iter().position(|h| h.eq_ignore_ascii_case("Email"));

  let mut wtr = csv::Writer::from_path("output.csv")?;
  wtr.write_record(&headers)?;

  for result in rdr.records() {
    let rec = result?;
    let mut row: Vec<String> = rec.iter().map(|s| s.to_string()).collect();
    if let Some(i) = email_idx {
      if i < row.len() { row[i] = row[i].trim().to_lowercase(); }
    }
    wtr.write_record(&row)?;
  }
  wtr.flush()?;
  Ok(())
}

