// C0666 · Merge sort (Intermedio, Algoritmos)
fn solve(mut a: Vec<i32>) -> Vec<i32> {
  let n = a.len();
  if n <= 1 { return a; }
  let mid = n/2;
  let left = solve(a.drain(0..mid).collect());
  let right= solve(a);
  let mut out = Vec::with_capacity(n);
  let mut i=0usize; let mut j=0usize;
  while i<left.len() && j<right.len() {
    if left[i] <= right[j] { out.push(left[i]); i+=1; } else { out.push(right[j]); j+=1; }
  }
  out.extend_from_slice(&left[i..]);
  out.extend_from_slice(&right[j..]);
  out
}

