// C0680 · Uso de teclado (keydown/atajos) (Intermedio, UI/Entrada)
// Rust · crossterm (teclas sin Enter)
// Cargo.toml: crossterm="*"
use crossterm::event::{read, Event, KeyCode, KeyEvent, KeyModifiers};

fn solve() -> crossterm::Result<()> {
  println!("Presiona teclas (q para salir, Ctrl+S demo).");
  loop {
    match read()? {
      Event::Key(KeyEvent { code, modifiers, .. }) => {
        if code == KeyCode::Char('q') { break; }
        if code == KeyCode::Char('s') && modifiers.contains(KeyModifiers::CONTROL) {
          println!("Atajo: Ctrl+S");
        }
        if code == KeyCode::Up || code == KeyCode::Char('w') { println!("Mover: arriba"); }
        if code == KeyCode::Down || code == KeyCode::Char('s') { println!("Mover: abajo"); }
        if code == KeyCode::Left || code == KeyCode::Char('a') { println!("Mover: izquierda"); }
        if code == KeyCode::Right || code == KeyCode::Char('d') { println!("Mover: derecha"); }
        if code == KeyCode::Esc { println!("Acción: cancelar"); }
        if code == KeyCode::Enter { println!("Acción: confirmar"); }
      }
      _ => {}
    }
  }
  Ok(())
}

